function setProfile(uint256 value) external onlyOwner {
  profileValue = value;
  emit ProfileUpdated(value);
}

modifier onlySessionOwner(uint256 id) {
  require(sessionOwner[id] == msg.sender, "not owner");
  _;
}

function claimInvoice(uint256 id) external {
  require(!invoiceClaimed[id], "already claimed");
  invoiceClaimed[id] = true;
  _mint(msg.sender, id);
}

function _authorizeWallet(address account) internal view {
  if (!hasRole(WALLET_ROLE, account)) {
    revert Unauthorized(account);
  }
}

